$(errorCatched(async () => {

  const PID = 'st-dash-deck-v1';

  let doc, win;
  try { doc = parent?.document || document; win = parent?.window || window; }
  catch (_) { doc = document; win = window; }

  [PID, `${PID}-css`, `${PID}-drawer`, `${PID}-overlay`].forEach(id => {
    doc.getElementById(id)?.remove();
  });

  const isMobile = win.innerWidth <= 768;
  let trigPos = { x: win.innerWidth - 64, y: Math.floor(win.innerHeight / 2) - 24 };
  try {
    const saved = JSON.parse(getVariables({ type: 'global' })?.['dashDeck_pos'] || 'null');
    if (saved) {
      trigPos.x = Math.max(0, Math.min(saved.x, win.innerWidth - 52));
      trigPos.y = Math.max(0, Math.min(saved.y, win.innerHeight - 52));
    }
  } catch (_) {}

  const css = doc.createElement('style');
  css.id = `${PID}-css`;
  css.textContent = `
    #${PID} {
      position: fixed; z-index: 2147483647;
      width: 48px; height: 48px;
      user-select: none; -webkit-user-select: none; touch-action: none;
      animation: ddeck-pop 0.3s cubic-bezier(0.22, 1, 0.36, 1) both;
    }
    @keyframes ddeck-pop {
      from { opacity: 0; transform: scale(0.4) rotate(-12deg); }
      to   { opacity: 1; transform: scale(1) rotate(0deg); }
    }
    #${PID} .deck__trigger {
      width: 48px; height: 48px; border-radius: 14px; border: none;
      background: rgba(16, 28, 52, 0.88);
      backdrop-filter: blur(12px); -webkit-backdrop-filter: blur(12px);
      box-shadow: 0 2px 16px rgba(0,0,0,0.35), inset 0 1px 0 rgba(255,255,255,0.12);
      cursor: pointer; display: flex; align-items: center; justify-content: center;
      transition: background 0.2s, box-shadow 0.2s, transform 0.2s;
      color: #7ecae3; position: relative;
    }
    #${PID} .deck__trigger:hover {
      background: rgba(20, 35, 62, 0.95);
      box-shadow: 0 4px 24px rgba(126, 202, 227, 0.3), inset 0 1px 0 rgba(255,255,255,0.15);
      transform: scale(1.1);
    }
    #${PID} .deck__trigger svg { transition: transform 0.3s ease; }
    #${PID}.is-open .deck__trigger svg { transform: rotate(-15deg) scale(1.1); }
    #${PID} .deck__badge {
      position: absolute; top: -4px; right: -4px; min-width: 18px; height: 18px;
      background: #7ecae3; color: #0d1a2e; font-size: 10px; font-weight: 800;
      border-radius: 9px; display: flex; align-items: center; justify-content: center;
      padding: 0 4px; box-shadow: 0 2px 6px rgba(0,0,0,0.3);
      opacity: 0; transform: scale(0); transition: all 0.2s cubic-bezier(0.22,1,0.36,1);
      font-family: 'Consolas', 'Monaco', monospace;
    }
    #${PID} .deck__badge.has-count { opacity: 1; transform: scale(1); }
    #${PID}-overlay {
      position: fixed; inset: 0; z-index: 2147483645;
      background: rgba(0, 0, 0, 0.35);
      opacity: 0; pointer-events: none; transition: opacity 0.25s ease;
    }
    #${PID}-overlay.is-visible { opacity: 1; pointer-events: all; }
    #${PID}-drawer {
      position: fixed; top: 0; right: 0; z-index: 2147483646;
      width: 340px; height: 100vh; max-height: 100vh;
      background: rgba(14, 22, 40, 0.96);
      backdrop-filter: blur(20px); -webkit-backdrop-filter: blur(20px);
      box-shadow: -4px 0 32px rgba(0,0,0,0.45);
      transform: translateX(100%); transition: transform 0.3s cubic-bezier(0.22, 1, 0.36, 1);
      display: flex; flex-direction: column;
      font-family: 'Microsoft YaHei', 'PingFang SC', system-ui, sans-serif;
      border-left: 1px solid rgba(126, 202, 227, 0.15);
    }
    @media (max-width: 768px) { #${PID}-drawer { width: 88vw; } }
    #${PID}-drawer.is-open { transform: translateX(0); }
    #${PID}-drawer .deck__header {
      padding: 18px 20px 14px; flex-shrink: 0;
      border-bottom: 1px solid rgba(126, 202, 227, 0.08);
      display: flex; align-items: center; justify-content: space-between;
    }
    #${PID}-drawer .deck__title {
      font-size: 15px; font-weight: 700; color: #dce8f0;
      letter-spacing: 0.04em;
    }
    #${PID}-drawer .deck__title-accent { color: #7ecae3; }
    #${PID}-drawer .deck__close-btn {
      width: 28px; height: 28px; border-radius: 6px; border: 1px solid rgba(255,255,255,0.1);
      background: transparent; color: rgba(255,255,255,0.45); cursor: pointer;
      display: flex; align-items: center; justify-content: center;
      font-size: 16px; transition: all 0.15s;
    }
    #${PID}-drawer .deck__close-btn:hover {
      background: rgba(126, 202, 227, 0.1); color: #fff;
      border-color: rgba(126, 202, 227, 0.3);
    }
    #${PID}-drawer .deck__body {
      flex: 1; overflow-y: auto; padding: 12px 16px 20px;
      scrollbar-width: thin; scrollbar-color: rgba(126,202,227,0.25) transparent;
    }
    #${PID}-drawer .deck__body::-webkit-scrollbar { width: 4px; }
    #${PID}-drawer .deck__body::-webkit-scrollbar-thumb {
      background: rgba(126,202,227,0.25); border-radius: 4px;
    }
    #${PID}-drawer .deck__section { margin-bottom: 6px; }
    #${PID}-drawer .deck__section-head {
      display: flex; align-items: center; justify-content: space-between;
      padding: 10px 12px; cursor: pointer; border-radius: 8px;
      background: rgba(126, 202, 227, 0.04); transition: background 0.15s; user-select: none;
    }
    #${PID}-drawer .deck__section-head:hover { background: rgba(126, 202, 227, 0.08); }
    #${PID}-drawer .deck__section-label {
      font-size: 12px; font-weight: 700; color: rgba(220, 235, 245, 0.8);
      letter-spacing: 0.06em; text-transform: uppercase;
    }
    #${PID}-drawer .deck__arrow {
      font-size: 14px; color: rgba(126, 202, 227, 0.4);
      transition: transform 0.25s ease; display: inline-block;
    }
    #${PID}-drawer .deck__section.is-collapsed .deck__arrow { transform: rotate(-90deg); }
    #${PID}-drawer .deck__section-body {
      padding: 10px 4px 6px; display: grid; gap: 6px;
      grid-template-columns: 1fr 1fr;
      overflow: hidden; transition: max-height 0.3s ease, opacity 0.2s ease, padding 0.3s ease;
    }
    #${PID}-drawer .deck__section-body.col-3 { grid-template-columns: 1fr 1fr 1fr; }
    #${PID}-drawer .deck__section.is-collapsed .deck__section-body {
      max-height: 0 !important; opacity: 0; padding-top: 0; padding-bottom: 0;
    }
    #${PID}-drawer .deck__chip {
      display: flex; align-items: center; gap: 6px;
      height: 32px; padding: 0 10px; border-radius: 8px;
      background: rgba(126, 202, 227, 0.05);
      border: 1px solid rgba(126, 202, 227, 0.1);
      cursor: pointer; transition: all 0.15s ease; overflow: hidden;
    }
    #${PID}-drawer .deck__chip:hover {
      background: rgba(126, 202, 227, 0.1);
      border-color: rgba(126, 202, 227, 0.2);
    }
    #${PID}-drawer .deck__chip-dot {
      width: 6px; height: 6px; border-radius: 50%; flex-shrink: 0;
      background: rgba(126, 202, 227, 0.2); transition: all 0.2s ease;
    }
    #${PID}-drawer .deck__chip-name {
      font-size: 11.5px; color: rgba(200, 220, 235, 0.65);
      white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
      line-height: 1; transition: color 0.15s;
    }
    #${PID}-drawer .deck__chip.is-active {
      background: rgba(126, 202, 227, 0.14);
      border-color: rgba(126, 202, 227, 0.4);
    }
    #${PID}-drawer .deck__chip.is-active .deck__chip-dot {
      background: #7ecae3; box-shadow: 0 0 8px rgba(126, 202, 227, 0.7);
    }
    #${PID}-drawer .deck__chip.is-active .deck__chip-name {
      color: #c8eaf5; font-weight: 600;
    }
    #${PID}-drawer .deck__group-hint {
      grid-column: 1 / -1; font-size: 10px; color: rgba(126,202,227,0.45);
      padding: 2px 6px; letter-spacing: 0.05em; user-select: none;
    }
    #${PID}-drawer .deck__footer {
      padding: 12px 20px; flex-shrink: 0;
      border-top: 1px solid rgba(126, 202, 227, 0.08);
      display: flex; justify-content: space-between; align-items: center;
    }
    #${PID}-drawer .deck__footer-text {
      font-size: 10.5px; color: rgba(200, 220, 235, 0.25); letter-spacing: 0.03em;
    }
    #${PID}-drawer .deck__footer-brand {
      font-size: 10.5px; color: #7ecae3; font-weight: 700;
      letter-spacing: 0.08em; cursor: default;
      transition: color 0.2s, text-shadow 0.2s;
    }
    #${PID}-drawer .deck__footer-brand:hover {
      color: #c8eaf5; text-shadow: 0 0 12px rgba(126,202,227,0.5);
    }
  `;
  doc.head.appendChild(css);

  const trigger = doc.createElement('div');
  trigger.id = PID;
  trigger.style.left = trigPos.x + 'px';
  trigger.style.top  = trigPos.y + 'px';
  trigger.innerHTML = `
    <button class="deck__trigger" id="${PID}-btn">
      <svg viewBox="0 0 24 24" width="26" height="26" fill="currentColor" stroke="currentColor" stroke-width="0.3">
        <path d="M12 11.5c-2.2-2.8-7-5.2-7.2-1.5-.2 3 4 4 7.2 1.5z"/>
        <path d="M12 11.5c2.2-2.8 7-5.2 7.2-1.5.2 3-4 4-7.2 1.5z"/>
        <circle cx="12" cy="11.8" r="1.8" stroke="none"/>
        <path d="M10.8 13.5Q11.2 17 10.2 20.5" fill="none" stroke-width="1.4" stroke-linecap="round"/>
        <path d="M13.2 13.5Q12.8 17 13.8 20.5" fill="none" stroke-width="1.4" stroke-linecap="round"/>
      </svg>
      <span class="deck__badge" id="${PID}-badge">0</span>
    </button>
  `;

  const overlay = doc.createElement('div');
  overlay.id = `${PID}-overlay`;

  const drawer = doc.createElement('div');
  drawer.id = `${PID}-drawer`;
  drawer.innerHTML = `
    <div class="deck__header">
      <div class="deck__title"><span class="deck__title-accent">🐾</span> 控制面板</div>
      <button class="deck__close-btn" id="${PID}-close">✕</button>
    </div>

    <div class="deck__body">

      <div class="deck__section">
        <div class="deck__section-head"><span class="deck__section-label">✎ 文风设定(单选)</span><span class="deck__arrow">›</span></div>
        <div class="deck__section-body" style="max-height:200px;">
          <div class="deck__chip" data-kw="文风" data-group="style">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">预设自带文风</span>
          </div>
          <div class="deck__chip" data-kw="自缝文风放置处" data-group="style">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">自己缝的文风</span>
          </div>
        </div>
      </div>

      <div class="deck__section">
        <div class="deck__section-head"><span class="deck__section-label">◎ 人称视角(单选)</span><span class="deck__arrow">›</span></div>
        <div class="deck__section-body col-3" style="max-height:400px;">
          <div class="deck__group-hint">▸ 抢话模式</div>
          <div class="deck__chip" data-kw="抢话 · 第一人称" data-group="pov">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">第一人称</span>
          </div>
          <div class="deck__chip" data-kw="抢话 · 第二人称" data-group="pov">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">第二人称</span>
          </div>
          <div class="deck__chip" data-kw="抢话 · 第三人称" data-group="pov">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">第三人称</span>
          </div>
          <div class="deck__group-hint">▸ 不抢话模式</div>
          <div class="deck__chip" data-kw="不抢话 · 第一人称" data-group="pov">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">第一人称</span>
          </div>
          <div class="deck__chip" data-kw="不抢话 · 第二人称" data-group="pov">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">第二人称</span>
          </div>
          <div class="deck__chip" data-kw="不抢话 · 第三人称" data-group="pov">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">第三人称</span>
          </div>
        </div>
      </div>

      <div class="deck__section">
        <div class="deck__section-head"><span class="deck__section-label">⚤ 涩涩词汇(多选)</span><span class="deck__arrow">›</span></div>
        <div class="deck__section-body" style="max-height:200px;">
          <div class="deck__chip" data-kw="女性词汇">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">女性词汇</span>
          </div>
          <div class="deck__chip" data-kw="男性词汇">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">男性词汇</span>
          </div>
        </div>
      </div>

      <div class="deck__section">
        <div class="deck__section-head"><span class="deck__section-label">⏱ 叙事节奏(单选)</span><span class="deck__arrow">›</span></div>
        <div class="deck__section-body col-3" style="max-height:200px;">
          <div class="deck__chip" data-kw="✨HBO超慢烧节奏(3选1)" data-group="pace">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">✨慢烧节奏</span>
          </div>
          <div class="deck__chip" data-kw="✨FX中等节奏(3选1)" data-group="pace">
            <span class="deck__chip-dot"></span><span class="deck__chip-name"> ✨中等节奏</span>
          </div>
          <div class="deck__chip" data-kw="✨SW快节奏(3选1)" data-group="pace">
            <span class="deck__chip-dot"></span><span class="deck__chip-name"> ✨快节奏</span>
          </div>
        </div>
      </div>

      <div class="deck__section">
        <div class="deck__section-head"><span class="deck__section-label">⚙ COT分支(多选)</span><span class="deck__arrow">›</span></div>
        <div class="deck__section-body" style="max-height:500px;">
          <div class="deck__chip" data-kw="时空背景">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">时空背景</span>
          </div>
          <div class="deck__chip" data-kw="次要事件">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">次要事件</span>
          </div>
          <div class="deck__chip" data-kw="角色纬度">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">角色维度</span>
          </div>
          <div class="deck__chip" data-kw="角色自主">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">角色自主</span>
          </div>
          <div class="deck__chip" data-kw="角色肢体语言">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">肢体语言</span>
          </div>
          <div class="deck__chip" data-kw="深度瑟瑟">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">深度瑟瑟</span>
          </div>
        </div>
      </div>

      <div class="deck__section">
        <div class="deck__section-head"><span class="deck__section-label">⬡ 功能模块(多选)</span><span class="deck__arrow">›</span></div>
        <div class="deck__section-body" style="max-height:200px;">
          <div class="deck__chip" data-kw="时间">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">时间</span>
          </div>
          <div class="deck__chip" data-kw="摘要">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">摘要</span>
          </div>
        </div>
      </div>

      <div class="deck__section">
        <div class="deck__section-head"><span class="deck__section-label">⊞ 底部越狱(单选)</span><span class="deck__arrow">›</span></div>
        <div class="deck__section-body col-3" style="max-height:200px;">
          <div class="deck__chip" data-kw="[mur鹿鹿] 非think底部" data-group="bottom">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">非think底部</span>
          </div>
          <div class="deck__chip" data-kw="[mur鹿鹿] think底部 1 " data-group="bottom">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">think底部 1</span>
          </div>
          <div class="deck__chip" data-kw="[mur鹿鹿] think底部 2" data-group="bottom">
            <span class="deck__chip-dot"></span><span class="deck__chip-name">think底部 2</span>
          </div>
        </div>
      </div>

    </div>

    <div class="deck__footer">
      <span class="deck__footer-text">Dash Deck v1.0</span>
      <span class="deck__footer-brand">mur鹿鹿</span>
    </div>
  `;

  const mountPoint = doc.documentElement || doc.body;
  mountPoint.appendChild(trigger);
  mountPoint.appendChild(overlay);
  mountPoint.appendChild(drawer);

  function findPrompts(keyword) {
    const list = doc.querySelector('#completion_prompt_manager_list');
    if (!list) return [];
    return [...list.querySelectorAll('li[data-pm-identifier]')].filter(li => {
      const nameEl = li.querySelector('[data-pm-name]');
      return nameEl && nameEl.getAttribute('data-pm-name').trim() === keyword.trim();
    });
  }

  function isEnabled(li) {
    return !li.classList.contains('completion_prompt_manager_prompt_disabled');
  }

  function clickSwitch(li) {
    const btn = li.querySelector('.prompt-manager-toggle-action');
    if (btn) btn.click();
  }

  function turnOn(keyword) {
    findPrompts(keyword).forEach(li => { if (!isEnabled(li)) clickSwitch(li); });
  }

  function turnOff(keyword) {
    findPrompts(keyword).forEach(li => { if (isEnabled(li)) clickSwitch(li); });
  }

  function isKeywordActive(keyword) {
    const items = findPrompts(keyword);
    return items.length > 0 && items.every(li => isEnabled(li));
  }

  let panelOpen = false;

  function openPanel() {
    panelOpen = true;
    drawer.classList.add('is-open');
    overlay.classList.add('is-visible');
    trigger.classList.add('is-open');
    syncAllChipStates();
  }

  function closePanel() {
    panelOpen = false;
    drawer.classList.remove('is-open');
    overlay.classList.remove('is-visible');
    trigger.classList.remove('is-open');
  }

  function togglePanel() { panelOpen ? closePanel() : openPanel(); }

  doc.getElementById(`${PID}-close`).addEventListener('click', closePanel);
  overlay.addEventListener('click', closePanel);

  drawer.querySelectorAll('.deck__chip').forEach(chip => {
    chip.addEventListener('click', () => {
      if (!doc.querySelector('#completion_prompt_manager_list')) {
        toastr.warning('请先打开预设管理面板（点击预设区域展开列表）');
        return;
      }

      const kw    = chip.getAttribute('data-kw');
      const group = chip.getAttribute('data-group');
      const wasOn = chip.classList.contains('is-active');

      if (wasOn) {
        turnOff(kw);
        chip.classList.remove('is-active');
      } else {
        if (group) {
          drawer.querySelectorAll(`.deck__chip[data-group="${group}"]`).forEach(other => {
            if (other !== chip) {
              turnOff(other.getAttribute('data-kw'));
              other.classList.remove('is-active');
            }
          });
        }
        turnOn(kw);
        chip.classList.add('is-active');
      }

      updateBadge();
    });
  });

  function syncAllChipStates() {
    if (!doc.querySelector('#completion_prompt_manager_list')) return;
    drawer.querySelectorAll('.deck__chip').forEach(chip => {
      const kw = chip.getAttribute('data-kw');
      chip.classList.toggle('is-active', isKeywordActive(kw));
    });
    updateBadge();
  }

  function updateBadge() {
    const count = drawer.querySelectorAll('.deck__chip.is-active').length;
    const badge = doc.getElementById(`${PID}-badge`);
    badge.textContent = count;
    badge.classList.toggle('has-count', count > 0);
  }

  setTimeout(syncAllChipStates, 1500);
  setTimeout(syncAllChipStates, 3000);

  drawer.querySelectorAll('.deck__section-head').forEach(head => {
    head.addEventListener('click', () => {
      const section = head.parentElement;
      const body = section.querySelector('.deck__section-body');
      if (section.classList.contains('is-collapsed')) {
        section.classList.remove('is-collapsed');
        body.style.maxHeight = body.scrollHeight + 'px';
      } else {
        body.style.maxHeight = body.scrollHeight + 'px';
        requestAnimationFrame(() => { section.classList.add('is-collapsed'); });
      }
    });
  });

  let dragging = false, dragMoved = false, offsetX = 0, offsetY = 0;

  function onDragStart(cx, cy) {
    dragging = true; dragMoved = false;
    const rect = trigger.getBoundingClientRect();
    offsetX = cx - rect.left;
    offsetY = cy - rect.top;
    trigger.style.transition = 'none';
  }
  function onDragMove(cx, cy) {
    if (!dragging) return;
    dragMoved = true;
    trigger.style.left = Math.max(4, Math.min(cx - offsetX, win.innerWidth  - 52)) + 'px';
    trigger.style.top  = Math.max(4, Math.min(cy - offsetY, win.innerHeight - 52)) + 'px';
  }
  function onDragEnd() {
    if (!dragging) return;
    dragging = false;
    trigger.style.transition = '';
    if (dragMoved) savePosition();
  }

  function savePosition() {
    try {
      insertOrAssignVariables({
        dashDeck_pos: JSON.stringify({
          x: parseInt(trigger.style.left),
          y: parseInt(trigger.style.top)
        })
      }, { type: 'global' });
    } catch (_) {}
  }

  const btn = doc.getElementById(`${PID}-btn`);
  btn.addEventListener('mousedown', e => { onDragStart(e.clientX, e.clientY); e.preventDefault(); });
  doc.addEventListener('mousemove', e => onDragMove(e.clientX, e.clientY));
  doc.addEventListener('mouseup', () => onDragEnd());
  btn.addEventListener('click', () => { if (!dragMoved) togglePanel(); dragMoved = false; });

  btn.addEventListener('touchstart', e => {
    onDragStart(e.touches[0].clientX, e.touches[0].clientY);
  }, { passive: true });
  btn.addEventListener('touchmove', e => {
    if (dragging) onDragMove(e.touches[0].clientX, e.touches[0].clientY);
  }, { passive: true });
  btn.addEventListener('touchend', e => {
    const wasMoved = dragMoved;
    onDragEnd();
    if (!wasMoved) togglePanel();
    e.preventDefault();
  }, { passive: false });

  try {
    if (parent && parent.document !== doc) {
      parent.document.addEventListener('mousemove', e => onDragMove(e.clientX, e.clientY));
      parent.document.addEventListener('mouseup', () => onDragEnd());
    }
  } catch (_) {}

  function cleanup() {
    doc.getElementById(PID)?.remove();
    doc.getElementById(`${PID}-css`)?.remove();
    doc.getElementById(`${PID}-drawer`)?.remove();
    doc.getElementById(`${PID}-overlay`)?.remove();
  }
  window.addEventListener('pagehide', cleanup);
  window.addEventListener('unload', cleanup);

}));
